];

const grants = [];

for (const program of grantPrograms) {
  const url = 'https://dced.pa.gov/programs/' + program.slug + '/';
  let description = '';
  let eligibility = '';
  let awardFloor = 0;
  let awardCeiling = 0;
  let deadline = 'See program guidelines';

  try {
    const html = await this.helpers.httpRequest({
      method: 'GET',
      url: url,
      headers: { 'User-Agent': 'Mozilla/5.0' },
      returnFullResponse: false,
    });

    if (typeof html === 'string') {
      // Extract description from entry-content or main content area
      const descMatch = html.match(/<div[^>]*class="[^"]*entry-content[^"]*"[^>]*>([\s\S]*?)<\/div>/i)
        || html.match(/<div[^>]*class="[^"]*program-description[^"]*"[^>]*>([\s\S]*?)<\/div>/i)
        || html.match(/<article[^>]*>([\s\S]*?)<\/article>/i);
      if (descMatch) {
        // Get text from first few paragraphs
        const paragraphs = descMatch[1].match(/<p[^>]*>([\s\S]*?)<\/p>/gi) || [];
        description = paragraphs.slice(0, 3)
          .map(p => p.replace(/<[^>]+>/g, '').trim())
          .filter(p => p.length > 20)
          .join(' ');
      }

      // Extract eligibility
      const eligMatch = html.match(/[Ee]ligib[a-z]*[^<]*<\/(?:h[2-4]|strong|b)>\s*(?:<[^>]+>)*\s*([\s\S]*?)(?=<\/div>|<h[2-4])/i);
      if (eligMatch) {
        eligibility = eligMatch[1].replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim().substring(0, 500);
      }

      // Extract funding amounts
      const amountMatch = html.match(/\$([\d,]+(?:\.\d{2})?)/g);
      if (amountMatch) {
        const amounts = amountMatch.map(a => parseInt(a.replace(/[$,]/g, ''))).filter(a => !isNaN(a) && a > 0);
        if (amounts.length > 0) {
          awardFloor = Math.min(...amounts);
          awardCeiling = Math.max(...amounts);
        }
      }

      // Extract deadline
      const deadlineMatch = html.match(/[Dd]eadline[^<]*(?:<[^>]+>)*\s*([^<]+)/)
        || html.match(/[Aa]pplications?\s+(?:must be|are due|due by|accepted until)[^<]*([^<]+)/)
        || html.match(/[Ss]ubmit(?:ted)? by\s+([A-Z][a-z]+ \d{1,2}(?:,? \d{4})?)/i);
      if (deadlineMatch) {
        deadline = deadlineMatch[1] ? deadlineMatch[1].replace(/<[^>]+>/g, '').trim() : deadline;
        if (deadline.length > 100) deadline = deadline.substring(0, 100);
      }
    }
  } catch(e) {
    // Page fetch failed, use basic data
  }

  const oppNum = 'PA-DCED-' + program.slug;

  grants.push({
    json: {
      id: oppNum,
      oppNum: oppNum,
      title: 'Pennsylvania: ' + program.name,
      description: description || ('PA DCED grant program. Visit ' + url + ' for full details.'),
      link: url,
      openDate: new Date().toISOString().split('T')[0],
      closeDate: deadline,
      agency: 'PA Dept of Community & Economic Development',
      agencyCode: 'PA-DCED',
      category: 'State Grant',
      source: 'Pennsylvania DCED',
      awardFloor: awardFloor,
      awardCeiling: awardCeiling,
      status: 'posted',
      metadata: {
        eligibility: eligibility || null,
        sourceLevel: 'state',
        state: 'Pennsylvania'
      }
    }
  });
}

return grants.length > 0 ? grants : [{ json: { empty: true, source: 'Pennsylvania DCED' } }];

// Parse ProPublica 990 data to find grant-making foundations
const items = $input.all();
const foundations = [];

for (const item of items) {
  let response = item.json;

  if (Array.isArray(response)) response = response[0];
  if (!response || response.error || response.statusCode >= 400) continue;

  // Handle search results
  const orgs = response.organizations || response.results || [];

  for (const org of orgs) {
    const name = (org.name || '').toLowerCase();
    const isFoundation = name.includes('foundation') || 
                         name.includes('trust') || 
                         name.includes('fund') ||
                         name.includes('endowment') ||
                         name.includes('philanthrop');

    if (!isFoundation) continue;

    const oppNum = 'PP-' + (org.ein || Date.now());

    foundations.push({
      json: {
        id: org.ein,
        oppNum: oppNum,
        title: org.name + ' - Potential Grant Source',
        description: 'Tax-exempt organization in ' + (org.city || 'Pennsylvania') + ', ' + (org.state || 'PA') + '. Review their 990 for grant-making activity.',
        link: 'https://projects.propublica.org/nonprofits/organizations/' + org.ein,
        openDate: new Date().toISOString().split('T')[0],
        closeDate: 'Ongoing - Contact directly',
        agency: org.name,
        agencyCode: '',
        category: 'Foundation',
        source: 'ProPublica 990',
        awardFloor: 0,
        awardCeiling: 0,
        status: 'active'
      }
    });
  }
}

return foundations.length > 0 ? foundations : [{ json: { empty: true, source: 'propublica' } }];

// Parse Philanthropy News Digest RSS for RFPs
const items = $input.all();
const rfps = [];

for (const item of items) {
  const rss = item.json.data || item.json.body || item.json;

  if (typeof rss !== 'string') continue;

  // Extract items from RSS
  const itemMatches = rss.match(/<item>([\s\S]*?)<\/item>/gi) || [];

  for (const itemXml of itemMatches) {
    const titleMatch = itemXml.match(/<title>([^<]+)<\/title>/);
    const linkMatch = itemXml.match(/<link>([^<]+)<\/link>/);
    const descMatch = itemXml.match(/<description>([^<]+)<\/description>/);
    const pubDateMatch = itemXml.match(/<pubDate>([^<]+)<\/pubDate>/);

    if (!titleMatch) continue;

    const title = titleMatch[1].replace(/<!\[CDATA\[|\]\]>/g, '').trim();
    const link = linkMatch ? linkMatch[1].trim() : '';
    const desc = descMatch ? descMatch[1].replace(/<!\[CDATA\[|\]\]>/g, '').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').trim() : '';
    const pubDate = pubDateMatch ? pubDateMatch[1].trim() : '';

    const oppNum = 'PND-' + Date.now() + '-' + Math.random().toString(36).substr(2, 5);

    rfps.push({
      json: {
        id: oppNum,
        oppNum: oppNum,
        title: title,
        description: desc.substring(0, 500),
        link: link,
        openDate: pubDate || new Date().toISOString().split('T')[0],
        closeDate: 'See RFP details',
        agency: 'Foundation (via PND)',
        agencyCode: '',
        category: 'Foundation RFP',
        source: 'Philanthropy News Digest',
        awardFloor: 0,
        awardCeiling: 0,
        status: 'posted'
      }
    });
  }
}

return rfps.length > 0 ? rfps : [{ json: { empty: true, source: 'pnd-rss' } }];

const items = $input.all();

  if (items.length === 1 && (items[0].json.noResults || items[0].json.noNewGrants)) {
    return items;
  }

  function extractDate(grant) {
    const candidates = [
      grant.closeDate,
      grant.deadline,
      grant.dueDate,
      grant.due_date,
      grant.endDate,
      grant.end_date,
      grant.applicationDeadline,
      grant.application_deadline,
    ];

    for (const val of candidates) {
      if (!val || typeof val !== 'string') continue;
      const parsed = new Date(val);
      if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 2000) {
        return parsed;
      }
    }

    if (grant.description) {
      const match = grant.description.match(/(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})|(\w+ \d{1,2},? \d{4})/);
      if (match) {
        const parsed = new Date(match[0]);
        if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 2000) {
          return parsed;
        }
      }
    }

    return null;
  }

  const withDeadline = [];
  const noDeadline = [];

  for (const item of items) {
    const date = extractDate(item.json);
    if (date) {
      item._sortDate = date;
      withDeadline.push(item);
    } else {
      noDeadline.push(item);
    }
  }

  withDeadline.sort((a, b) => a._sortDate - b._sortDate);

  const combined = [...withDeadline, ...noDeadline];
  return combined.map(item => ({ json: item.json }));

// Input: $input.all() contains items from the HTTP Request node
const items = $input.all();
const grants = [];

for (const item of items) {
    const html = item.json.data; // raw HTML from SAM.gov opportunities page
    if (!html) continue;

    // Regex to extract each table row inside <tbody>
    const rowRegex = /<tr[^>]*>([\s\S]*?)<\/tr>/gi;
    let match;

    while ((match = rowRegex.exec(html)) !== null) {
        const rowHtml = match[1];

        // Extract each <td> content in this row
        const tdRegex = /<td[^>]*>[\s\S]*?<div[^>]*>([\s\S]*?)<\/div>[\s\S]*?<\/td>/gi;
        let tdMatch;
        const tds = [];
        while ((tdMatch = tdRegex.exec(rowHtml)) !== null) {
            let value = tdMatch[1]
                .replace(/<[^>]+>/g, '')  // remove inner HTML tags
                .replace(/&nbsp;/g, ' ')
                .trim();
            tds.push(value);
        }

        // Check if row has at least the expected columns (Close date, Status, Title, Agency, Award min, Award max)
        if (tds.length < 6) continue;

        grants.push({
            json: {
                id: 'SAM-' + tds[2].replace(/\s+/g, '-').substring(0, 50) + '-' + Date.now(),
                title: tds[2] || 'No title',
                description: '', // optional, could add opportunity number from hidden div if needed
