  if (closedTerms.test(title)) continue;
  if (!/challenge|fund|grant|impact|initiative|open|apply/i.test(title + ' ' + url)) continue;
  seen.add(url);
  const slug = url.replace(/^https?:\/\//, '').replace(/[^a-z0-9]+/gi, '-').slice(0, 80);
  grants.push({ json: {
    id: 'GOOGLE-' + slug,
    oppNum: 'GOOGLE-' + slug,
    title: title,
    description: 'Google.org funding opportunity. Visit ' + url + ' for eligibility, deadlines, and application details.',
    link: url,
    openDate: new Date().toISOString().split('T')[0],
    closeDate: 'See listing',
    agency: 'Google.org',
    agencyCode: 'GOOGLE',
    category: 'Philanthropic - Corporate',
    source: 'Google.org',
    awardFloor: 0,
    awardCeiling: 0,
    status: 'posted',
    metadata: { sourceLevel: 'philanthropic', funder: 'Google.org' }
  }});
}
return grants.length > 0 ? grants : [{ json: { empty: true, source: 'Google.org' } }];
